# ─── Config ───────────────────────────────────────────────────────────────────

CONFIG_FILE = Path.home() / ".gam_gui_config.json"
DEFAULT_CONFIG = {
    "gam_path": "gam",
    "confirm_destructive": True,
    "output_lines": 2000,
}

def load_config():
    if CONFIG_FILE.exists():
        try:
            with open(CONFIG_FILE) as f:
                data = json.load(f)
            cfg = DEFAULT_CONFIG.copy()
            cfg.update(data)
            return cfg
        except Exception:
            pass
    return DEFAULT_CONFIG.copy()

def save_config(cfg):
    with open(CONFIG_FILE, "w") as f:
        json.dump(cfg, f, indent=2)

