# ─── Chromebook Batch Window ───────────────────────────────────────────────────

class ChromebookBatchWindow(tk.Toplevel):
    """Spreadsheet-style batch editor for Chromebook operations."""

    def __init__(self, parent, config_data, output_callback, history_callback):
        super().__init__(parent)
        self.title("Chromebook Batch Manager")
        self.geometry("1020x680")
        self.minsize(800, 520)
        self.config_data = config_data
        self._output_cb = output_callback
        self._history_cb = history_callback
        self._rows = []
        self._cell_vars = {}
        self._run_btn = None
        self._status_var = tk.StringVar(value="Ready — create a new batch or import a CSV.")
        self._progress_var = tk.StringVar(value="")
        self.colors = parent.colors
        self.configure(bg=self.colors["bg"])
        self._build_ui()
        self._new_batch()

    # ── UI ─────────────────────────────────────────────────────────────────

    def _build_ui(self):
        c = self.colors

        # Toolbar
        tb = tk.Frame(self, bg=c["sidebar"], height=46)
        tb.pack(fill="x")
        tb.pack_propagate(False)

        tk.Label(tb, text="⬡  Chromebook Batch Manager", bg=c["sidebar"], fg=c["fg"],
                 font=("Segoe UI", 11, "bold")).pack(side="left", padx=14, pady=12)

        for lbl, cmd in [("📄 New",          self._new_batch),
                          ("📂 Import CSV",   self._import_csv),
                          ("💾 Export CSV",   self._export_csv),
                          ("📋 Template",     self._download_template)]:
            tk.Button(tb, text=lbl, bg=c["sidebar"], fg=c["fg2"], relief="flat",
                      font=("Segoe UI", 9), cursor="hand2",
                      activebackground=c["sel"], activeforeground=c["accent"],
                      command=cmd).pack(side="left", padx=3, pady=10)

        # Quick-fill controls
        sep = tk.Frame(tb, bg=c["border"], width=1)
        sep.pack(side="left", fill="y", padx=8, pady=8)

        tk.Label(tb, text="Fill action:", bg=c["sidebar"], fg=c["fg2"],
                 font=("Segoe UI", 9)).pack(side="left", padx=(0, 4))
        self._batch_action = tk.StringVar(value="move_ou")
        cb = ttk.Combobox(tb, textvariable=self._batch_action, width=13,
                          values=sorted(VALID_ACTIONS), state="readonly",
                          font=("Segoe UI", 9))
        cb.pack(side="left", pady=10)
        cb.bind("<<ComboboxSelected>>", lambda e: self._fill_column("action", self._batch_action.get()))

        tk.Label(tb, text="OU:", bg=c["sidebar"], fg=c["fg2"],
                 font=("Segoe UI", 9)).pack(side="left", padx=(10, 4))
        self._batch_ou = tk.StringVar()
        tk.Entry(tb, textvariable=self._batch_ou, bg=c["entry_bg"], fg=c["fg"],
                 insertbackground=c["fg"], relief="flat", bd=3,
                 font=("Segoe UI", 9), width=18).pack(side="left", pady=10)
        tk.Button(tb, text="Fill OU", bg=c["sidebar"], fg=c["fg2"], relief="flat",
                  font=("Segoe UI", 9), cursor="hand2",
                  activebackground=c["sel"], activeforeground=c["accent"],
                  command=lambda: self._fill_column("ou", self._batch_ou.get().strip())
                  ).pack(side="left", padx=4, pady=10)

        # Run button
        self._run_btn = tk.Button(tb, text="▶  Run batch",
                                  bg=c["accent"], fg="white",
                                  font=("Segoe UI", 10, "bold"), relief="flat",
                                  cursor="hand2", padx=14, pady=5,
                                  activebackground="#1a5fcc",
                                  command=self._run_batch)
        self._run_btn.pack(side="right", padx=10, pady=8)

        # Status bar
        tk.Label(self, textvariable=self._status_var, bg=c["bg"], fg=c["fg2"],
                 font=("Segoe UI", 9), anchor="w").pack(fill="x", padx=14, pady=(6, 0))

        # Column header legend
        legend = tk.Frame(self, bg=c["bg"])
        legend.pack(fill="x", padx=14, pady=(2, 0))
        tk.Label(legend, text="deviceId takes priority if both are filled  |  ",
                 bg=c["bg"], fg=c["fg2"], font=("Segoe UI", 8)).pack(side="left")
        for col in CROS_BATCH_COLUMNS:
            req = " *" if col["required"] else ""
            tk.Label(legend, text=f"{col['name']}{req}", bg=c["bg"],
                     fg=c["accent"] if col["required"] else c["fg2"],
                     font=("Segoe UI", 8)).pack(side="left", padx=4)

        # Grid canvas
        grid_outer = tk.Frame(self, bg=c["bg"])
        grid_outer.pack(fill="both", expand=True, padx=12, pady=6)

        self._vscroll = ttk.Scrollbar(grid_outer, orient="vertical")
        self._hscroll = ttk.Scrollbar(grid_outer, orient="horizontal")
        self._canvas = tk.Canvas(grid_outer, bg=c["bg"], highlightthickness=0,
                                  yscrollcommand=self._vscroll.set,
                                  xscrollcommand=self._hscroll.set)
        self._vscroll.configure(command=self._canvas.yview)
        self._hscroll.configure(command=self._canvas.xview)
        self._vscroll.pack(side="right", fill="y")
        self._hscroll.pack(side="bottom", fill="x")
        self._canvas.pack(side="left", fill="both", expand=True)

        self._grid_inner = tk.Frame(self._canvas, bg=c["bg"])
        self._cwin = self._canvas.create_window((0, 0), window=self._grid_inner, anchor="nw")
        self._grid_inner.bind("<Configure>",
                               lambda e: self._canvas.configure(
                                   scrollregion=self._canvas.bbox("all")))
        self._canvas.bind("<Configure>",
                           lambda e: self._canvas.itemconfig(self._cwin, width=e.width))
        self._canvas.bind("<MouseWheel>",
                           lambda e: self._canvas.yview_scroll(-1 * (e.delta // 120), "units"))

        # Bottom row controls
        bot = tk.Frame(self, bg=c["sidebar"], height=36)
        bot.pack(fill="x", side="bottom")
        bot.pack_propagate(False)

        for lbl, cmd in [("+ Add row",     self._add_row),
                          ("− Remove last", self._remove_last_row),
                          ("✕ Clear all",   self._clear_all)]:
            tk.Button(bot, text=lbl, bg=c["sidebar"], fg=c["fg2"], relief="flat",
                      font=("Segoe UI", 9), cursor="hand2",
                      activebackground=c["sel"], activeforeground=c["accent"],
                      command=cmd).pack(side="left", padx=6, pady=6)

        tk.Label(bot, textvariable=self._progress_var, bg=c["sidebar"], fg=c["fg2"],
                 font=("Segoe UI", 9)).pack(side="right", padx=14)

    # ── Grid ───────────────────────────────────────────────────────────────

    def _render_grid(self):
        c = self.colors
        for w in self._grid_inner.winfo_children():
            w.destroy()
        self._cell_vars.clear()

        # Header
        tk.Label(self._grid_inner, text="#", bg=c["sidebar"], fg=c["fg2"],
                 font=("Segoe UI", 8, "bold"), width=3, anchor="center",
                 relief="flat").grid(row=0, column=0, padx=(0, 1), pady=(0, 2), sticky="ew")

        for ci, col in enumerate(CROS_BATCH_COLUMNS):
            req = " *" if col["required"] else ""
            bg = c["sel"] if col["required"] else c["sidebar"]
            fg = c["accent"] if col["required"] else c["fg2"]
            tk.Label(self._grid_inner, text=f"{col['name']}{req}",
                     bg=bg, fg=fg, font=("Segoe UI", 8, "bold"),
                     width=col["width"] // 8, anchor="w", padx=4,
                     relief="flat").grid(row=0, column=ci+1, padx=1, pady=(0, 2), sticky="ew")

        # Data rows
        for ri, row_data in enumerate(self._rows):
            row_bg = c["entry_bg"] if ri % 2 == 0 else c["bg"]

            tk.Label(self._grid_inner, text=str(ri + 1), bg=row_bg, fg=c["fg2"],
                     font=("Segoe UI", 8), width=3,
                     anchor="center").grid(row=ri+1, column=0, padx=(0, 1), pady=1, sticky="ew")

            for ci, col in enumerate(CROS_BATCH_COLUMNS):
                var = tk.StringVar(value=row_data.get(col["name"], ""))
                self._cell_vars[(ri, col["name"])] = var

                cell_bg = row_bg
                if col["required"] and not var.get():
                    cell_bg = "#1a0d1a"

                e = tk.Entry(self._grid_inner, textvariable=var,
                             bg=cell_bg, fg=c["fg"],
                             insertbackground=c["fg"], relief="flat", bd=2,
                             font=("Segoe UI", 9), width=col["width"] // 8)
                e.grid(row=ri+1, column=ci+1, padx=1, pady=1, sticky="ew")
                var.trace_add("write",
                              lambda *a, r=ri, cn=col["name"]: self._cell_changed(r, cn))

        for ci in range(len(CROS_BATCH_COLUMNS) + 1):
            self._grid_inner.columnconfigure(ci, weight=1 if ci > 0 else 0)

        self._update_status()

    def _cell_changed(self, row_idx, col_name):
        if (row_idx, col_name) in self._cell_vars:
            if row_idx < len(self._rows):
                self._rows[row_idx][col_name] = self._cell_vars[(row_idx, col_name)].get()

    def _sync_vars(self):
        for (ri, cn), var in self._cell_vars.items():
            if ri < len(self._rows):
                self._rows[ri][cn] = var.get()

    def _update_status(self):
        total = len(self._rows)
        valid = sum(
            1 for r in self._rows
            if (r.get("serialNumber", "").strip() or r.get("deviceId", "").strip())
            and r.get("action", "").strip()
        )
        self._status_var.set(
            f"{total} rows  —  {valid} ready  —  {total - valid} missing required fields")

    # ── Row management ─────────────────────────────────────────────────────

    def _blank_row(self):
        return {col["name"]: "" for col in CROS_BATCH_COLUMNS}

    def _new_batch(self):
        self._rows = [self._blank_row() for _ in range(6)]
        self._render_grid()
        self._status_var.set("New batch — fill in device IDs and actions, then click ▶ Run batch.")

    def _add_row(self):
        self._sync_vars()
        self._rows.append(self._blank_row())
        self._render_grid()

    def _remove_last_row(self):
        self._sync_vars()
        if self._rows:
            self._rows.pop()
            self._render_grid()

    def _clear_all(self):
        if messagebox.askyesno("Clear all rows", "Remove all rows?", parent=self):
            self._rows = []
            self._render_grid()

    def _fill_column(self, col_name, value):
        if not value:
            messagebox.showwarning("Empty value",
                                   f"Enter a value to fill into '{col_name}'.", parent=self)
            return
        self._sync_vars()
        for i, row in enumerate(self._rows):
            row[col_name] = value
            if (i, col_name) in self._cell_vars:
                self._cell_vars[(i, col_name)].set(value)

    # ── CSV import / export ────────────────────────────────────────────────

    def _import_csv(self):
        path = filedialog.askopenfilename(
            title="Import Chromebook CSV",
            filetypes=[("CSV files", "*.csv"), ("All files", "*.*")],
            parent=self)
        if not path:
            return
        col_names = [col["name"] for col in CROS_BATCH_COLUMNS]
        try:
            with open(path, newline="", encoding="utf-8-sig") as f:
                reader = csv.DictReader(f)
                imported = []
                for row in reader:
                    r = self._blank_row()
                    for k in col_names:
                        if k in row:
                            r[k] = row[k].strip()
                    imported.append(r)
            if not imported:
                messagebox.showwarning("Empty file", "No data rows found in the CSV.", parent=self)
                return
            self._rows = imported
            self._render_grid()
            self._status_var.set(
                f"Imported {len(imported)} rows from {Path(path).name}")
        except Exception as e:
            messagebox.showerror("Import error", str(e), parent=self)

    def _export_csv(self):
        self._sync_vars()
        path = filedialog.asksaveasfilename(
            title="Export batch CSV",
            defaultextension=".csv",
            filetypes=[("CSV files", "*.csv")],
            initialfile=f"chromebook_batch_{datetime.now().strftime('%Y%m%d_%H%M%S')}.csv",
            parent=self)
        if not path:
            return
        col_names = [col["name"] for col in CROS_BATCH_COLUMNS]
        try:
            with open(path, "w", newline="", encoding="utf-8") as f:
                writer = csv.DictWriter(f, fieldnames=col_names)
                writer.writeheader()
                for row in self._rows:
                    writer.writerow(row)
            self._status_var.set(f"Exported {len(self._rows)} rows to {Path(path).name}")
        except Exception as e:
            messagebox.showerror("Export error", str(e), parent=self)

    def _download_template(self):
        path = filedialog.asksaveasfilename(
            title="Save CSV template",
            defaultextension=".csv",
            filetypes=[("CSV files", "*.csv")],
            initialfile="chromebook_batch_template.csv",
            parent=self)
        if not path:
            return
        try:
            with open(path, "w", newline="", encoding="utf-8") as f:
                writer = csv.writer(f)
                for row in TEMPLATE_ROWS:
                    writer.writerow(row)
            messagebox.showinfo(
                "Template saved",
                f"Template saved to:\n{path}\n\n"
                "Open in Excel or Google Sheets, fill in your device IDs, "
                "then use Import CSV to load it back here.",
                parent=self)
        except Exception as e:
            messagebox.showerror("Error", str(e), parent=self)

    # ── Batch execution ────────────────────────────────────────────────────

    def _run_batch(self):
        self._sync_vars()
        gam = self.config_data.get("gam_path", "gam")

        commands = []
        errors = []
        for i, row in enumerate(self._rows):
            serial = row.get("serialNumber", "").strip()
            dev    = row.get("deviceId",    "").strip()
            action = row.get("action",      "").strip().lower()
            if not serial and not dev and not action:
                continue  # fully blank row
            if not serial and not dev:
                continue  # no identifier — skip silently
            if not action:
                errors.append(f"Row {i+1}: missing action")
                continue
            if action not in VALID_ACTIONS:
                errors.append(
                    f"Row {i+1}: unknown action '{action}' "
                    f"(valid: {', '.join(sorted(VALID_ACTIONS))})")
                continue
            # deviceId takes priority; fall back to serialNumber
            use_serial = bool(serial) and not bool(dev)
            identifier = dev if dev else serial
            cmd = self._build_cmd(gam, identifier, action, row, use_serial)
            if cmd is None:
                errors.append(f"Row {i+1}: action '{action}' requires 'ou' field")
                continue
            if len(cmd) == 0:
                errors.append(f"Row {i+1}: annotate requires at least one of: "
                               "assetId, location, user, notes")
                continue
            commands.append((i + 1, cmd))

        if errors:
            messagebox.showerror(
                "Validation errors",
                "Fix these before running:\n\n" + "\n".join(errors),
                parent=self)
            return

        if not commands:
            messagebox.showwarning(
                "Nothing to run",
                "No valid rows found. Fill in serialNumber or deviceId (or both), plus action.", parent=self)
            return

        if self.config_data.get("confirm_destructive", True):
            destructive_count = sum(
                1 for _, c in commands
                if "deprovision" in c or ("action" in c and "disable" in c))
            msg = f"Run {len(commands)} GAM command(s)?"
            if destructive_count:
                msg += f"\n\n⚠️  {destructive_count} row(s) include destructive operations."
            if not messagebox.askyesno("Confirm batch run", msg, parent=self):
                return

        self._run_btn.configure(state="disabled", text="Running…")
        self._progress_var.set(f"0 / {len(commands)}")

        def worker():
            for idx, (row_num, cmd) in enumerate(commands):
                self.after(0, self._progress_var.set,
                           f"{idx} / {len(commands)}  (row {row_num})")
                self.after(0, self._output_cb,
                           f"\n[Row {row_num}] $ {' '.join(cmd)}\n", "cmd")
                self._history_cb({
                    "time": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
                    "cmd":  " ".join(cmd),
                })
                try:
                    proc = subprocess.Popen(
                        cmd, stdout=subprocess.PIPE, stderr=subprocess.STDOUT,
                        text=True, encoding="utf-8", errors="replace")
                    for line in proc.stdout:
                        self.after(0, self._output_cb, line)
                    proc.wait()
                    if proc.returncode == 0:
                        self.after(0, self._output_cb, f"✓ Row {row_num} OK\n", "ok")
                    else:
                        self.after(0, self._output_cb,
                                   f"✗ Row {row_num} failed (exit {proc.returncode})\n", "err")
                except FileNotFoundError:
                    self.after(0, self._output_cb,
                               f"✗ GAM not found: '{cmd[0]}'\n", "err")
                    break
                except Exception as e:
                    self.after(0, self._output_cb, f"✗ Error: {e}\n", "err")

            done = len(commands)
            self.after(0, self._progress_var.set, f"✓ {done} / {done} done")
            self.after(0, lambda: self._run_btn.configure(
                state="normal", text="▶  Run batch"))

        threading.Thread(target=worker, daemon=True).start()

    def _build_cmd(self, gam, identifier, action, row, use_serial=False):
        # Serial:    gam update cros query:id:<serial> ...
        # Device ID: gam update cros <deviceId> ...
        dev_args = ["query:id:" + identifier] if use_serial else [identifier]

        if action == "move_ou":
            ou = row.get("ou", "").strip()
            if not ou:
                return None
            return [gam, "update", "cros"] + dev_args + ["ou", ou]
        elif action == "disable":
            return [gam, "update", "cros"] + dev_args + ["action", "disable"]
        elif action == "reenable":
            return [gam, "update", "cros"] + dev_args + ["action", "reenable"]
        elif action == "deprovision":
            return ([gam, "update", "cros"] + dev_args +
                    ["action", "deprovision", "acknowledge_device_touch_requirement"])
        elif action == "annotate":
            cmd = [gam, "update", "cros"] + dev_args
            for field, gam_key in [("assetId",  "assetid"),
                                    ("location", "location"),
                                    ("user",     "user"),
                                    ("notes",    "notes")]:
                val = row.get(field, "").strip()
                if val:
                    cmd += [gam_key, val]
            return cmd if len(cmd) > 4 else []
        return None


# ─── Main Application ──────────────────────────────────────────────────────────

class GAMGui(tk.Tk):
    def __init__(self):
        super().__init__()
        self.config_data = load_config()
        self.title("GAM GUI Manager")
        self.geometry("1100x720")
        self.minsize(860, 580)
        self._setup_styles()
        self._build_ui()
        self._check_gam()

    # ── Styles ─────────────────────────────────────────────────────────────

    def _setup_styles(self):
        style = ttk.Style(self)
        style.theme_use("clam")

        BG      = "#0d1117"
        SIDEBAR = "#090c11"
        ACCENT  = "#2979ff"
        FG      = "#dce6ff"
        FG2     = "#6b82b8"
        ENTRY   = "#131b2e"
        SEL     = "#0d2051"
        DANGER  = "#e53935"
        SUCCESS = "#00c98d"
        BORDER  = "#1a2847"

        self.colors = {
            "bg": BG, "sidebar": SIDEBAR, "accent": ACCENT,
            "fg": FG, "fg2": FG2, "entry_bg": ENTRY,
            "sel": SEL, "danger": DANGER, "success": SUCCESS,
            "border": BORDER,
        }
        self.configure(bg=BG)

        style.configure("TFrame",       background=BG)
        style.configure("TLabel",       background=BG, foreground=FG, font=("Segoe UI", 10))
        style.configure("TButton",      background=ENTRY, foreground=FG, relief="flat",
                        font=("Segoe UI", 9), padding=(10, 5), borderwidth=0)
        style.map("TButton",
                  background=[("active", BORDER), ("pressed", "#1e2230")],
                  foreground=[("active", FG)])

        style.configure("Accent.TButton", background=ACCENT, foreground="white",
                        font=("Segoe UI", 10, "bold"), padding=(14, 7))
        style.map("Accent.TButton",
                  background=[("active", "#1a5fcc")],
                  foreground=[("active", "white")])

        style.configure("Danger.TButton", background=DANGER, foreground="white",
                        font=("Segoe UI", 10, "bold"), padding=(14, 7))
        style.map("Danger.TButton",
                  background=[("active", "#c94040")],
                  foreground=[("active", "white")])

        style.configure("TNotebook",     background=BG, borderwidth=0)
        style.configure("TNotebook.Tab", background=ENTRY, foreground=FG2,
                        font=("Segoe UI", 9), padding=(12, 5))
        style.map("TNotebook.Tab",
                  background=[("selected", BG)],
                  foreground=[("selected", ACCENT)])

        style.configure("Vertical.TScrollbar",   background=ENTRY, troughcolor=SIDEBAR,
                        arrowcolor=FG2, borderwidth=0, relief="flat")
        style.configure("Horizontal.TScrollbar", background=ENTRY, troughcolor=SIDEBAR,
                        arrowcolor=FG2, borderwidth=0, relief="flat")

        style.configure("TCombobox", fieldbackground=ENTRY, background=ENTRY,
                        foreground=FG, selectbackground=SEL, selectforeground=FG)

    # ── Main UI ────────────────────────────────────────────────────────────

    def _build_ui(self):
        c = self.colors

        # Top bar
        topbar = tk.Frame(self, bg=c["sidebar"], height=52)
        topbar.pack(fill="x", side="top")
        topbar.pack_propagate(False)

        # Viking logo
        try:
            from PIL import Image, ImageTk
            img_data = base64.b64decode(VIKING_LOGO_B64)
            img = Image.open(io.BytesIO(img_data)).resize((34, 34), Image.LANCZOS)
            self._logo_img = ImageTk.PhotoImage(img)
            tk.Label(topbar, image=self._logo_img, bg=c["sidebar"]).pack(side="left", padx=(12, 6), pady=9)
        except Exception:
            # Fallback: draw a simple placeholder if PIL not available
            logo_canvas = tk.Canvas(topbar, width=34, height=34, bg=c["sidebar"],
                                    highlightthickness=0)
            logo_canvas.pack(side="left", padx=(12, 6), pady=9)
            logo_canvas.create_oval(2, 2, 32, 32, fill=c["accent"], outline="")
            logo_canvas.create_text(18, 18, text="V", fill="white",
                                    font=("Segoe UI", 14, "bold"))

        # Thin accent line left of title
        tk.Frame(topbar, bg=c["accent"], width=2, height=28).pack(side="left", pady=12, padx=(0, 8))

        tk.Label(topbar, text="GAM GUI Manager", bg=c["sidebar"], fg=c["fg"],
                 font=("Segoe UI", 12, "bold")).pack(side="left", pady=10)

        self._gam_status_var   = tk.StringVar(value="Checking GAM…")
        self._gam_status_label = tk.Label(topbar, textvariable=self._gam_status_var,
                                          bg=c["sidebar"], fg=c["fg2"],
                                          font=("Segoe UI", 9))
        self._gam_status_label.pack(side="right", padx=16)

        tk.Button(topbar, text="⚙ Settings", bg=c["sidebar"], fg=c["fg2"], relief="flat",
                  font=("Segoe UI", 9), cursor="hand2",
                  activebackground=c["sel"], activeforeground=c["accent"],
                  command=self._open_settings).pack(side="right", padx=4, pady=10)

        tk.Button(topbar, text="📋 History", bg=c["sidebar"], fg=c["fg2"], relief="flat",
                  font=("Segoe UI", 9), cursor="hand2",
                  activebackground=c["sel"], activeforeground=c["accent"],
                  command=self._open_history).pack(side="right", padx=4, pady=10)

        # Body
        body = tk.Frame(self, bg=c["bg"])
        body.pack(fill="both", expand=True)

        # Sidebar
        sidebar = tk.Frame(body, bg=c["sidebar"], width=170)
        sidebar.pack(fill="y", side="left")
        sidebar.pack_propagate(False)

        tk.Label(sidebar, text="CATEGORIES", bg=c["sidebar"], fg=c["fg2"],
                 font=("Segoe UI", 7, "bold")).pack(anchor="w", padx=12, pady=(14, 4))

        self._cat_buttons = {}
        all_cats = list(COMMANDS.keys()) + ["Chromebook Batch"]
        for cat in all_cats:
            icon = "📊 " if cat == "Chromebook Batch" else "  "
            btn = tk.Button(sidebar, text=f"{icon}{cat}",
                            bg=c["sidebar"], fg=c["fg2"], font=("Segoe UI", 9),
                            relief="flat", anchor="w", cursor="hand2",
                            activebackground=c["sel"], activeforeground=c["accent"],
                            command=lambda c_=cat: self._select_category(c_))
            btn.pack(fill="x", padx=4, pady=1)
            self._cat_buttons[cat] = btn

        tk.Frame(sidebar, bg=c["border"], height=1).pack(fill="x", padx=8, pady=8)

        custom_btn = tk.Button(sidebar, text="  ✏ Custom command",
                               bg=c["sidebar"], fg=c["fg2"], font=("Segoe UI", 9),
                               relief="flat", anchor="w", cursor="hand2",
                               activebackground=c["sel"], activeforeground=c["accent"],
                               command=lambda: self._select_category("__custom__"))
        custom_btn.pack(fill="x", padx=4, pady=1)
        self._cat_buttons["__custom__"] = custom_btn

        # Command list panel
        self._cmd_list_frame = tk.Frame(body, bg=c["bg"], width=240)
        self._cmd_list_frame.pack(fill="y", side="left")
        self._cmd_list_frame.pack_propagate(False)

        tk.Label(self._cmd_list_frame, text="COMMANDS", bg=c["bg"], fg=c["fg2"],
                 font=("Segoe UI", 7, "bold")).pack(anchor="w", padx=12, pady=(14, 4))

        cmd_outer = tk.Frame(self._cmd_list_frame, bg=c["bg"])
        cmd_outer.pack(fill="both", expand=True, padx=4)

        self._cmd_canvas = tk.Canvas(cmd_outer, bg=c["bg"], highlightthickness=0)
        cmd_scrollbar = ttk.Scrollbar(cmd_outer, orient="vertical",
                                      command=self._cmd_canvas.yview)
        self._cmd_inner = tk.Frame(self._cmd_canvas, bg=c["bg"])
        self._cmd_inner.bind("<Configure>",
                              lambda e: self._cmd_canvas.configure(
                                  scrollregion=self._cmd_canvas.bbox("all")))
        self._cmd_canvas.create_window((0, 0), window=self._cmd_inner, anchor="nw")
        self._cmd_canvas.configure(yscrollcommand=cmd_scrollbar.set)
        self._cmd_canvas.pack(side="left", fill="both", expand=True)
        cmd_scrollbar.pack(side="right", fill="y")

        # Right panel
        right = tk.Frame(body, bg=c["bg"])
        right.pack(fill="both", side="left", expand=True)

        tk.Frame(body, bg=c["border"], width=1).place(relx=0, rely=0, relheight=1)

        # Form area
        self._form_frame = tk.Frame(right, bg=c["bg"])
        self._form_frame.pack(fill="x", padx=20, pady=(16, 8))

        self._cmd_title = tk.Label(self._form_frame, text="Select a command",
                                   bg=c["bg"], fg=c["fg"],
                                   font=("Segoe UI", 14, "bold"))
        self._cmd_title.pack(anchor="w")

        self._cmd_help = tk.Label(self._form_frame,
                                  text="Choose a category and command from the left panel.",
                                  bg=c["bg"], fg=c["fg2"],
                                  font=("Segoe UI", 9, "italic"),
                                  wraplength=540, justify="left")
        self._cmd_help.pack(anchor="w", pady=(2, 10))

        self._fields_frame = tk.Frame(self._form_frame, bg=c["bg"])
        self._fields_frame.pack(fill="x")

        self._btn_frame = tk.Frame(self._form_frame, bg=c["bg"])
        self._btn_frame.pack(anchor="w", pady=(10, 0))

        self._preview_var = tk.StringVar(value="")
        tk.Label(self._form_frame, textvariable=self._preview_var,
                 bg=c["bg"], fg=c["fg2"], font=("Courier New", 9),
                 wraplength=540, justify="left").pack(anchor="w", pady=(4, 0))

        # Output area
        out_bar = tk.Frame(right, bg=c["bg"])
        out_bar.pack(fill="x", padx=20, pady=(4, 0))
        tk.Label(out_bar, text="OUTPUT", bg=c["bg"], fg=c["fg2"],
                 font=("Segoe UI", 7, "bold")).pack(side="left")
        for lbl, cmd in [("Clear", self._clear_output),
                          ("Copy",  self._copy_output),
                          ("Save…", self._save_output)]:
            tk.Button(out_bar, text=lbl, bg=c["bg"], fg=c["fg2"], relief="flat",
                      font=("Segoe UI", 8), cursor="hand2",
                      command=cmd).pack(side="right", padx=3)

        self._output = scrolledtext.ScrolledText(
            right, bg=c["entry_bg"], fg=c["fg"],
            font=("Courier New", 9), relief="flat",
            insertbackground=c["fg"], wrap=tk.NONE,
            state="disabled", height=12)
        self._output.pack(fill="both", expand=True, padx=20, pady=(4, 4))

        self._output.tag_config("err",  foreground=c["danger"])
        self._output.tag_config("ok",   foreground=c["success"])
        self._output.tag_config("info", foreground=c["accent"])
        self._output.tag_config("cmd",  foreground="#4db6ff")

        hscroll = ttk.Scrollbar(right, orient="horizontal", command=self._output.xview)
        hscroll.pack(fill="x", padx=20, pady=(0, 8))
        self._output["xscrollcommand"] = hscroll.set

        # State
        self._current_cmd  = None
        self._field_vars   = {}
        self._cmd_buttons  = {}
        self._run_button   = None
        self._history      = []
        self._custom_var   = None

        first_cat = next(iter(COMMANDS))
        self._select_category(first_cat)

    # ── Category / command selection ───────────────────────────────────────

    def _select_category(self, category):
        c = self.colors
        for cat, btn in self._cat_buttons.items():
            if cat == category:
                btn.configure(bg=c["sel"], fg=c["accent"], font=("Segoe UI", 9, "bold"))
            else:
                btn.configure(bg=c["sidebar"], fg=c["fg2"], font=("Segoe UI", 9))

        for w in self._cmd_inner.winfo_children():
            w.destroy()
        self._cmd_buttons.clear()

        if category == "__custom__":
            self._show_custom_form()
            return

        if category == "Chromebook Batch":
            self._open_chromebook_batch()
            return

        cmds = COMMANDS[category]
        for i, cmd_def in enumerate(cmds):
            is_destructive = cmd_def.get("destructive", False)
            fg_color = c["danger"] if is_destructive else c["fg"]
            btn = tk.Button(
                self._cmd_inner, text=f"  {cmd_def['label']}",
                bg=c["bg"], fg=fg_color, font=("Segoe UI", 9),
                relief="flat", anchor="w", cursor="hand2",
                activebackground=c["entry_bg"], activeforeground=c["accent"],
                command=lambda i_=i, cat_=category: self._select_command(cat_, i_))
            btn.pack(fill="x", pady=1, padx=2)
            self._cmd_buttons[(category, i)] = btn

        if cmds:
            self._select_command(category, 0)

    def _select_command(self, category, index):
        c = self.colors
        cmd_def = COMMANDS[category][index]

        for (cat, i), btn in self._cmd_buttons.items():
            if cat == category and i == index:
                btn.configure(bg=c["entry_bg"], fg=c["accent"])
            else:
                is_d = COMMANDS[cat][i].get("destructive", False)
                btn.configure(bg=c["bg"], fg=c["danger"] if is_d else c["fg"])

        self._current_cmd = cmd_def
        self._build_form(cmd_def)

    def _open_chromebook_batch(self):
        def output_cb(text, tag=None):
            self._append_output(text, tag)
        def history_cb(entry):
            self._history.append(entry)
        win = ChromebookBatchWindow(self, self.config_data, output_cb, history_cb)
        win.grab_set()

    # ── Form building ──────────────────────────────────────────────────────

    def _build_form(self, cmd_def):
        c = self.colors
        is_destructive = cmd_def.get("destructive", False)

        for w in self._fields_frame.winfo_children():
            w.destroy()
        for w in self._btn_frame.winfo_children():
            w.destroy()
        self._field_vars.clear()

        self._cmd_title.configure(text=cmd_def["label"],
                                  fg=c["danger"] if is_destructive else c["fg"])
        self._cmd_help.configure(text=cmd_def.get("help", ""))

        for field in cmd_def.get("fields", []):
            row = tk.Frame(self._fields_frame, bg=c["bg"])
            row.pack(fill="x", pady=3)

            lbl_text = field["name"].replace("_", " ").title()
            if field.get("required"):
                lbl_text += " *"
            tk.Label(row, text=lbl_text, bg=c["bg"], fg=c["fg2"],
                     font=("Segoe UI", 9), width=16, anchor="e").pack(side="left", padx=(0, 8))

            var = tk.StringVar()
            entry = tk.Entry(row, textvariable=var,
                             bg=c["entry_bg"], fg=c["fg2"],
                             insertbackground=c["fg"], relief="flat",
                             font=("Segoe UI", 10), bd=4)
            placeholder = field.get("placeholder", "")
            entry.insert(0, placeholder)
            entry.bind("<FocusIn>",  lambda e, p=placeholder, v=var, w=entry:
                       self._clear_placeholder(w, p, v))
            entry.bind("<FocusOut>", lambda e, p=placeholder, v=var, w=entry:
                       self._restore_placeholder(w, p, v))
            entry.pack(side="left", fill="x", expand=True)
            entry.bind("<KeyRelease>", lambda e: self._update_preview())
            self._field_vars[field["name"]] = (var, placeholder)

        style = "Danger.TButton" if is_destructive else "Accent.TButton"
        label = "⚠️  Run (destructive)" if is_destructive else "▶  Run command"
        self._run_button = ttk.Button(self._btn_frame, text=label,
                                      style=style, command=self._run_command)
        self._run_button.pack(side="left")
        ttk.Button(self._btn_frame, text="Clear fields", style="TButton",
                   command=self._clear_fields).pack(side="left", padx=8)

        self._update_preview()

    def _show_custom_form(self):
        c = self.colors
        for w in self._fields_frame.winfo_children():
            w.destroy()
        for w in self._btn_frame.winfo_children():
            w.destroy()
        self._field_vars.clear()
        self._current_cmd = None
        self._preview_var.set("")

        self._cmd_title.configure(text="Custom GAM command", fg=c["fg"])
        self._cmd_help.configure(
            text="Enter any GAM arguments (everything after 'gam').")

        row = tk.Frame(self._fields_frame, bg=c["bg"])
        row.pack(fill="x", pady=3)
        tk.Label(row, text="gam", bg=c["bg"], fg=c["accent"],
                 font=("Courier New", 11, "bold")).pack(side="left", padx=(0, 6))

        self._custom_var = tk.StringVar()
        tk.Entry(row, textvariable=self._custom_var,
                 bg=c["entry_bg"], fg=c["fg"],
                 insertbackground=c["fg"], relief="flat",
                 font=("Courier New", 10), bd=4).pack(side="left", fill="x", expand=True)

        ttk.Button(self._btn_frame, text="▶  Run", style="Accent.TButton",
                   command=self._run_custom).pack(side="left")

    # ── Placeholder helpers ────────────────────────────────────────────────

    def _clear_placeholder(self, widget, placeholder, var):
        if widget.get() == placeholder:
            widget.delete(0, "end")
            widget.configure(fg=self.colors["fg"])

    def _restore_placeholder(self, widget, placeholder, var):
        if not widget.get():
            widget.insert(0, placeholder)
            widget.configure(fg=self.colors["fg2"])

    def _clear_fields(self):
        for name, (var, placeholder) in self._field_vars.items():
            var.set("")
        self._update_preview()

    # ── Command preview ────────────────────────────────────────────────────

    def _update_preview(self):
        if not self._current_cmd:
            self._preview_var.set("")
            return
        try:
            args = self._resolve_args(self._current_cmd)
            gam = self.config_data.get("gam_path", "gam")
            self._preview_var.set(f"$ {gam} {' '.join(args)}")
        except Exception:
            self._preview_var.set("")

    def _resolve_args(self, cmd_def):
        args = []
        for part in cmd_def["cmd"]:
            if part.startswith("{") and part.endswith("}"):
                key = part[1:-1]
                if key in self._field_vars:
                    val, placeholder = self._field_vars[key]
                    v = val.get()
                    if v == placeholder:
                        v = ""
                    args.append(v)
                else:
                    args.append(part)
            else:
                args.append(part)
        return args

    # ── Run command ────────────────────────────────────────────────────────

    def _run_command(self):
        if not self._current_cmd:
            return
        for field in self._current_cmd.get("fields", []):
            if field.get("required"):
                var, placeholder = self._field_vars[field["name"]]
                v = var.get()
                if not v or v == placeholder:
                    messagebox.showwarning("Missing field",
                                           f"'{field['name']}' is required.")
                    return

        if self._current_cmd.get("confirm") and self.config_data.get("confirm_destructive", True):
            args = self._resolve_args(self._current_cmd)
            gam  = self.config_data.get("gam_path", "gam")
            if not messagebox.askyesno("Confirm action",
                                        f"Run this command?\n\n{gam} {' '.join(args)}"):
                return

        self._execute(self._resolve_args(self._current_cmd))

    def _run_custom(self):
        import shlex
        raw = (self._custom_var.get() if self._custom_var else "").strip()
        if not raw:
            return
        try:
            args = shlex.split(raw)
        except ValueError as e:
            messagebox.showerror("Parse error", str(e))
            return
        self._execute(args)

    def _execute(self, args):
        gam_path = self.config_data.get("gam_path", "gam")
        full_cmd = [gam_path] + [a for a in args if a]

        self._history.append({
            "time": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
            "cmd":  " ".join(full_cmd),
        })
        self._append_output(f"\n$ {' '.join(full_cmd)}\n", "cmd")

        if self._run_button:
            self._run_button.configure(state="disabled")

        def worker():
            try:
                proc = subprocess.Popen(
                    full_cmd, stdout=subprocess.PIPE, stderr=subprocess.STDOUT,
                    text=True, encoding="utf-8", errors="replace")
                for line in proc.stdout:
                    self.after(0, self._append_output, line)
                proc.wait()
                if proc.returncode == 0:
                    self.after(0, self._append_output, "\n✓ Completed (exit 0)\n", "ok")
                else:
                    self.after(0, self._append_output,
                               f"\n✗ Exited with code {proc.returncode}\n", "err")
            except FileNotFoundError:
                self.after(0, self._append_output,
                           f"\n✗ GAM not found: '{gam_path}'\n"
                           f"   Open Settings to set the correct path.\n", "err")
            except Exception as e:
                self.after(0, self._append_output, f"\n✗ Error: {e}\n", "err")
            finally:
                if self._run_button:
                    self.after(0, lambda: self._run_button.configure(state="normal"))

        threading.Thread(target=worker, daemon=True).start()

    # ── Output helpers ─────────────────────────────────────────────────────

    def _append_output(self, text, tag=None):
        self._output.configure(state="normal")
        max_lines = self.config_data.get("output_lines", 2000)
        lines = int(self._output.index("end-1c").split(".")[0])
        if lines > max_lines:
            self._output.delete("1.0", f"{lines - max_lines}.0")
        if tag:
            self._output.insert("end", text, tag)
        else:
            self._output.insert("end", text)
        self._output.see("end")
        self._output.configure(state="disabled")

    def _clear_output(self):
        self._output.configure(state="normal")
        self._output.delete("1.0", "end")
        self._output.configure(state="disabled")

    def _copy_output(self):
        self.clipboard_clear()
        self.clipboard_append(self._output.get("1.0", "end"))

    def _save_output(self):
        path = filedialog.asksaveasfilename(
            defaultextension=".txt",
            filetypes=[("Text files", "*.txt"), ("CSV files", "*.csv"), ("All files", "*.*")],
            title="Save output")
        if path:
            with open(path, "w", encoding="utf-8") as f:
                f.write(self._output.get("1.0", "end"))

    # ── GAM check ─────────────────────────────────────────────────────────

    def _check_gam(self):
        gam = self.config_data.get("gam_path", "gam")
        found = shutil.which(gam) or os.path.isfile(gam)
        if found:
            self._gam_status_label.configure(fg=self.colors["success"])
            self._gam_status_var.set(f"✓ GAM: {gam}")
        else:
            self._gam_status_label.configure(fg=self.colors["danger"])
            self._gam_status_var.set(f"✗ GAM not found: {gam}")

    # ── Settings ───────────────────────────────────────────────────────────

    def _open_settings(self):
        c = self.colors
        win = tk.Toplevel(self)
        win.title("Settings")
        win.geometry("480x260")
        win.configure(bg=c["bg"])
        win.resizable(False, False)

        tk.Label(win, text="Settings", bg=c["bg"], fg=c["fg"],
                 font=("Segoe UI", 13, "bold")).pack(anchor="w", padx=20, pady=(16, 8))

        frame = tk.Frame(win, bg=c["bg"])
        frame.pack(fill="x", padx=20)

        def field_row(label):
            r = tk.Frame(frame, bg=c["bg"])
            r.pack(fill="x", pady=5)
            tk.Label(r, text=label, bg=c["bg"], fg=c["fg2"],
                     font=("Segoe UI", 9), width=22, anchor="e").pack(side="left", padx=(0, 8))
            return r

        r1 = field_row("GAM path / command")
        gam_var = tk.StringVar(value=self.config_data.get("gam_path", "gam"))
        tk.Entry(r1, textvariable=gam_var, bg=c["entry_bg"], fg=c["fg"],
                 insertbackground=c["fg"], relief="flat", bd=4,
                 font=("Segoe UI", 10)).pack(side="left", fill="x", expand=True)
        tk.Button(r1, text="Browse…", bg=c["entry_bg"], fg=c["fg2"], relief="flat",
                  font=("Segoe UI", 8), cursor="hand2",
                  command=lambda: gam_var.set(
                      filedialog.askopenfilename(title="Locate GAM binary") or gam_var.get()
                  )).pack(side="left", padx=(4, 0))

        r2 = field_row("Confirm before running")
        confirm_var = tk.BooleanVar(value=self.config_data.get("confirm_destructive", True))
        tk.Checkbutton(r2, variable=confirm_var, bg=c["bg"], fg=c["fg"],
                       selectcolor=c["entry_bg"],
                       activebackground=c["bg"]).pack(side="left")

        r3 = field_row("Max output lines")
        lines_var = tk.IntVar(value=self.config_data.get("output_lines", 2000))
        tk.Entry(r3, textvariable=lines_var, bg=c["entry_bg"], fg=c["fg"],
                 insertbackground=c["fg"], relief="flat", bd=4,
                 font=("Segoe UI", 10), width=8).pack(side="left")

        def save_and_close():
            self.config_data["gam_path"]           = gam_var.get().strip()
            self.config_data["confirm_destructive"] = confirm_var.get()
            self.config_data["output_lines"]        = lines_var.get()
            save_config(self.config_data)
            self._check_gam()
            win.destroy()

        bot = tk.Frame(win, bg=c["bg"])
        bot.pack(side="bottom", fill="x", padx=20, pady=16)
        ttk.Button(bot, text="Save & close", style="Accent.TButton",
                   command=save_and_close).pack(side="right")
        ttk.Button(bot, text="Cancel", style="TButton",
                   command=win.destroy).pack(side="right", padx=8)

    # ── History ────────────────────────────────────────────────────────────

    def _open_history(self):
        c = self.colors
        win = tk.Toplevel(self)
        win.title("Command history")
        win.geometry("700x420")
        win.configure(bg=c["bg"])

        tk.Label(win, text="Command history", bg=c["bg"], fg=c["fg"],
                 font=("Segoe UI", 13, "bold")).pack(anchor="w", padx=20, pady=(16, 8))

        text = scrolledtext.ScrolledText(win, bg=c["entry_bg"], fg=c["fg"],
                                          font=("Courier New", 9), relief="flat")
        text.pack(fill="both", expand=True, padx=20, pady=(0, 12))

        if not self._history:
            text.insert("end", "No commands run yet.")
        else:
            for h in reversed(self._history):
                text.insert("end", f"[{h['time']}]  {h['cmd']}\n")
        text.configure(state="disabled")


# ─── Entry point ──────────────────────────────────────────────────────────────

if __name__ == "__main__":
    app = GAMGui()
    app.mainloop()
